const items = $input.all();
const results = [];

for (const item of items) {
  // Récupérer les paramètres depuis l'URL du webhook (query params)
  const params = item.json.query || item.json.body || item.json;

  // Extraire toutes les données nécessaires
  const dossierNumero = params.dossier || params.YNUM_0;
  const reponse = params.reponse;
  const email_validation = params.email;
  const telegram_id = params.telegram_id || null;

  // Log pour debug - voir ce qui arrive au webhook
  console.log('Données reçues par le webhook:', params);

  // Préparer les données pour la mise à jour selon l'API Sage X3
  const updatePayload = {
    YNUM_0: dossierNumero,
    YVALIDG_0: reponse === 'oui' ? true : false,
    YDATVAL_0: new Date().toISOString().split('T')[0],
    YCOMM_0: reponse === 'oui' 
      ? 'Validé par PDG via email' 
      : 'Refusé par PDG via email'
  };

  results.push({
    json: {
      // Données originales du webhook
      webhook_data: params,

      // Données extraites
      dossier: dossierNumero,
      reponse: reponse,
      email: email_validation,
      telegram_id: telegram_id,
      statut: reponse === 'oui' ? 'Validé' : 'Refusé',

      // Payload pour l'API
      updatePayload: updatePayload,

      // Date de traitement
      date_traitement: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const processData = $('Process Validation2').item.json;
  const putData = $('PUT - Update Dossier').item.json; // Données du PUT
  const dossierFromGet = item.json; // Données du GET depuis Sage

  const reponse = processData.reponse;
  const dossierNumero = dossierFromGet.YNUM;
  const email = processData.email;
  const telegram_id = processData.telegram_id;

  // Récupérer les informations personnelles depuis webhook_data
  const webhookData = processData.webhook_data || {};
  const prenom = webhookData.prenom || 'Non renseigné';
  const nom = webhookData.nom || 'Non renseigné';
  const nomComplet = `${prenom} ${nom}`.trim();
  const matricule = webhookData.matricule || 'Non renseigné';
  const poste = webhookData.poste || 'Non renseigné';
  const cin = webhookData.cin || 'Non renseigné';

  // Extraire le statut de validation depuis YVALIDG (du PUT qui est la source de vérité)
  const isValidated = putData.YVALIDG === true;
  const isDisabled = putData.$properties?.YVALIDG?.$isDisabled === true;

  // Récupérer le message de diagnostic depuis le PUT (prioritaire)
  let diagnosticMessage = '';
  let isAlreadyProcessed = false;

  // Vérifier d'abord dans le PUT data (source principale)
  if (putData.$diagnoses && Array.isArray(putData.$diagnoses)) {
    const diagnosis = putData.$diagnoses.find(d => d.$severity === 'info');
    if (diagnosis && diagnosis.$message) {
      diagnosticMessage = diagnosis.$message;
      // Vérifier si le dossier était déjà validé
      if (diagnosticMessage.toLowerCase().includes('deja valide') || 
          diagnosticMessage.toLowerCase().includes('déjà validé')) {
        isAlreadyProcessed = true;
      }
    }
  }

  // Si pas de diagnostic dans PUT, vérifier dans GET (fallback)
  if (!diagnosticMessage && dossierFromGet.$diagnoses && Array.isArray(dossierFromGet.$diagnoses)) {
    const diagnosis = dossierFromGet.$diagnoses.find(d => d.$severity === 'info');
    if (diagnosis && diagnosis.$message) {
      diagnosticMessage = diagnosis.$message;
      if (diagnosticMessage.toLowerCase().includes('deja valide') || 
          diagnosticMessage.toLowerCase().includes('déjà validé')) {
        isAlreadyProcessed = true;
      }
    }
  }

  // Extraire les informations du dossier Sage (priorité au PUT)
  const etag = putData.$etag || dossierFromGet.$etag;
  const dateValidationSage = putData.YDATVAL ? new Date(putData.YDATVAL).toLocaleDateString('fr-FR') : 
                              (dossierFromGet.YDATVAL ? new Date(dossierFromGet.YDATVAL).toLocaleDateString('fr-FR') : 'N/A');
  const commentaireSage = putData.YCOMM || dossierFromGet.YCOMM || 'Aucun commentaire';
  const utilisateurSage = putData.$actxUser || dossierFromGet.$actxUser || 'N/A';
  const dossierSage = putData.$actxFolder || dossierFromGet.$actxFolder || 'N/A';
  const solutionSage = putData.$actxSolution || dossierFromGet.$actxSolution || 'N/A';

  const dateValidation = putData.YDATVAL || dossierFromGet.YDATVAL || new Date().toISOString().split('T')[0];
  const commentaire = putData.YCOMM || dossierFromGet.YCOMM || (reponse === 'oui' ? 'Validé par PDG via email' : 'Refusé par PDG via email');

  // Déterminer le statut dynamique
  let statut;
  let statutBadgeClass;
  let emoji;

  if (isAlreadyProcessed) {
    statut = isValidated ? 'Déjà validé' : 'Déjà traité';
    statutBadgeClass = 'status-warning';
    emoji = '⚠️';
  } else {
    statut = isValidated ? 'Validé avec succès' : 'Refusé';
    statutBadgeClass = isValidated ? 'status-success' : 'status-error';
    emoji = isValidated ? '✅' : '❌';
  }

  // Préparer le message de confirmation pour Telegram
  let message_text = `${emoji} *${statut.toUpperCase()}*\n\n` +
                      `📋 *Informations du dossier*\n` +
                      `Numéro: \`${dossierNumero}\`\n` +
                      `👤 Candidat: ${nomComplet}\n` +
                      `🆔 Matricule: ${matricule}\n` +
                      `📍 Poste: ${poste}\n` +
                      `🆔 CIN: ${cin}\n`;

  // Ajouter le message de diagnostic s'il existe
  if (diagnosticMessage) {
    message_text += `\n💬 _${diagnosticMessage}_`;
  }

  // Ajouter la date de validation si déjà traité
  if (isAlreadyProcessed && dateValidationSage !== 'N/A') {
    message_text += `\n📅 _Validé le ${dateValidationSage}_`;
  }

  // HTML pour email avec toutes les informations
  const response_html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { 
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; 
      display: flex; 
      justify-content: center; 
      align-items: center; 
      min-height: 100vh; 
      margin: 0; 
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); 
      padding: 20px;
    }
    .card { 
      background: white; 
      padding: 40px; 
      border-radius: 15px; 
      box-shadow: 0 10px 40px rgba(0,0,0,0.3); 
      max-width: 700px; 
      width: 100%;
    }
    .header {
      text-align: center;
      margin-bottom: 30px;
    }
    .icon { font-size: 80px; margin-bottom: 20px; }
    h1 { 
      color: #333; 
      margin-bottom: 10px; 
      font-size: 28px; 
      text-align: center;
    }
    .subtitle {
      text-align: center;
      color: #666;
      font-size: 16px;
      margin-bottom: 30px;
    }
    .section {
      margin: 25px 0;
      padding: 20px;
      background: #f9f9f9;
      border-radius: 8px;
      border-left: 4px solid #667eea;
    }
    .section-title {
      font-size: 18px;
      font-weight: bold;
      color: #333;
      margin-bottom: 15px;
      display: flex;
      align-items: center;
      gap: 10px;
    }
    .info-row {
      display: flex;
      justify-content: space-between;
      padding: 10px 0;
      border-bottom: 1px solid #e0e0e0;
    }
    .info-row:last-child {
      border-bottom: none;
    }
    .info-label {
      font-weight: 600;
      color: #555;
      min-width: 180px;
    }
    .info-value {
      color: #333;
      text-align: right;
      flex: 1;
    }
    .dossier-badge { 
      background: #667eea;
      color: white;
      padding: 15px 25px;
      border-radius: 8px;
      text-align: center;
      font-weight: bold; 
      font-size: 20px;
      margin: 20px 0;
    }
    .status-badge {
      display: inline-block;
      padding: 8px 16px;
      border-radius: 20px;
      font-weight: bold;
      font-size: 14px;
    }
    .status-success {
      background: #d4edda;
      color: #155724;
    }
    .status-error {
      background: #f8d7da;
      color: #721c24;
    }
    .status-warning {
      background: #fff3cd;
      color: #856404;
    }
    .warning {
      background: #fff3cd;
      border: 2px solid #ffc107;
      padding: 15px;
      border-radius: 8px;
      margin-top: 20px;
      color: #856404;
      display: flex;
      align-items: center;
      gap: 10px;
    }
    .diagnostic-box {
      background: #e3f2fd;
      border-left: 4px solid #2196f3;
      padding: 15px;
      border-radius: 8px;
      margin: 20px 0;
      color: #0d47a1;
    }
    .footer {
      margin-top: 30px;
      padding-top: 20px;
      border-top: 2px solid #f0f0f0;
      color: #888;
      font-size: 14px;
      text-align: center;
    }
    @media only screen and (max-width: 600px) {
      .info-row {
        flex-direction: column;
        gap: 5px;
      }
      .info-label {
        min-width: auto;
      }
      .info-value {
        text-align: left;
      }
    }
  </style>
</head>
<body>
  <div class="card">
    <div class="header">
      <div class="icon">${emoji}</div>
      <h1>${statut}</h1>
      <p class="subtitle">Le dossier de recrutement a été traité ${isAlreadyProcessed ? '(déjà traité précédemment)' : 'avec succès'}.</p>
      <span class="status-badge ${statutBadgeClass}">${statut}</span>
    </div>

    <div class="dossier-badge">📋 Dossier N° ${dossierNumero}</div>

    ${diagnosticMessage ? `
    <div class="diagnostic-box">
      <strong>💬 Message système:</strong><br>
      ${diagnosticMessage}
    </div>
    ` : ''}

    ${isAlreadyProcessed ? `
    <div class="warning">
      <span style="font-size: 24px;">⚠️</span>
      <div>
        <strong>Information:</strong> Ce dossier était déjà validé le ${dateValidationSage}
      </div>
    </div>
    ` : ''}

    <!-- Informations du Candidat -->
    <div class="section">
      <div class="section-title">
        👤 Informations du Candidat
      </div>
      <div class="info-row">
        <span class="info-label">Nom complet:</span>
        <span class="info-value"><strong>${nomComplet}</strong></span>
      </div>
      <div class="info-row">
        <span class="info-label">Matricule:</span>
        <span class="info-value">${matricule}</span>
      </div>
      <div class="info-row">
        <span class="info-label">Poste demandé:</span>
        <span class="info-value">${poste}</span>
      </div>
      <div class="info-row">
        <span class="info-label">CIN:</span>
        <span class="info-value">${cin}</span>
      </div>
    </div>


    <div class="footer">
      <p><strong>Service SI/IA</strong></p>
      <p>Cette notification a été générée automatiquement par le système Sage X3.</p>
      <p style="margin-top: 10px; font-size: 12px;">Merci de ne pas répondre à ce message.</p>
    </div>
  </div>
</body>
</html>`;

  results.push({
    json: {
      dossier: dossierNumero,
      reponse: reponse,
      email: email,
      telegram_id: telegram_id,
      statut: statut,
      date_validation: dateValidation,
      message_text: message_text,
      response_html: response_html,

      // Informations personnelles du candidat
      candidat_info: {
        prenom: prenom,
        nom: nom,
        nom_complet: nomComplet,
        matricule: matricule,
        poste: poste,
        cin: cin
      },

      // Informations de diagnostic
      diagnostic_info: {
        message: diagnosticMessage,
        is_already_processed: isAlreadyProcessed,
        is_validated: isValidated,
        source: diagnosticMessage ? (putData.$diagnoses ? 'PUT' : 'GET') : 'none'
      },

      // Détails du dossier Sage
      dossier_details: {
        etag: etag,
        folder: dossierSage,
        solution: solutionSage,
        user: utilisateurSage,
        date_validation_sage: dateValidationSage,
        commentaire_sage: commentaireSage,
        isAlreadyValidated: isValidated,
        isDisabled: isDisabled,
        commentaire: commentaire
      },

      success: true,
      skipUpdate: isAlreadyProcessed // Flag pour sauter le PUT si déjà traité
    }
  });
}

return results;
